import { useState, useEffect } from 'react';
import API from '../../services/axios';

const STYLES = `
  @keyframes fadeUp   { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
  @keyframes countUp  { from{opacity:0} to{opacity:1} }
  @keyframes pulse    { 0%,100%{transform:scale(1)} 50%{transform:scale(1.04)} }
  @keyframes shimmer  { 0%{background-position:-200px 0} 100%{background-position:200px 0} }
  .card-hover { transition: transform 0.2s ease, box-shadow 0.2s ease; }
  .card-hover:hover { transform: translateY(-4px); box-shadow: 0 12px 40px rgba(0,0,0,0.12) !important; }
`;

const ICONS = {
  revenue:  { icon: '₹', bg: 'linear-gradient(135deg,#f093fb,#f5576c)', shadow: 'rgba(240,147,251,0.4)' },
  bookings: { icon: '🎫', bg: 'linear-gradient(135deg,#4facfe,#00f2fe)', shadow: 'rgba(79,172,254,0.4)' },
  events:   { icon: '🎭', bg: 'linear-gradient(135deg,#43e97b,#38f9d7)', shadow: 'rgba(67,233,123,0.4)' },
  users:    { icon: '👥', bg: 'linear-gradient(135deg,#fa709a,#fee140)', shadow: 'rgba(250,112,154,0.4)' },
  cancel:   { icon: '❌', bg: 'linear-gradient(135deg,#f77062,#fe5196)', shadow: 'rgba(247,112,98,0.4)' },
  pending:  { icon: '⏳', bg: 'linear-gradient(135deg,#f6d365,#fda085)', shadow: 'rgba(246,211,101,0.4)' },
};

function StatCard({ type, label, value, sub, trend }) {
  const cfg = ICONS[type];
  return (
    <div className="card-hover" style={{
      background: 'white', borderRadius: '24px', padding: '1.5rem',
      boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0',
      animation: 'fadeUp 0.5s ease', position: 'relative', overflow: 'hidden',
    }}>
      {/* Background blob */}
      <div style={{
        position: 'absolute', top: '-30px', right: '-30px',
        width: '100px', height: '100px', borderRadius: '50%',
        background: cfg.bg, opacity: 0.08,
      }} />

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div style={{ flex: 1 }}>
          <p style={{ color: '#999', fontSize: '0.72rem', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '1px', margin: '0 0 10px' }}>{label}</p>
          <p style={{ color: '#1a1a2e', fontSize: '2rem', fontWeight: '900', margin: '0 0 8px', fontFamily: "'Cormorant Garamond', serif", lineHeight: 1 }}>{value}</p>
          {sub && (
            <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
              <span style={{
                fontSize: '0.7rem', fontWeight: '700', padding: '3px 8px', borderRadius: '20px',
                background: trend === 'up' ? '#e8f5e9' : trend === 'down' ? '#fdeee9' : '#f5f5f5',
                color: trend === 'up' ? '#2e7d32' : trend === 'down' ? '#c62828' : '#888',
              }}>
                {trend === 'up' ? '▲' : trend === 'down' ? '▼' : '●'} {sub}
              </span>
            </div>
          )}
        </div>
        <div style={{
          width: '52px', height: '52px', borderRadius: '16px',
          background: cfg.bg, display: 'flex', alignItems: 'center',
          justifyContent: 'center', fontSize: type === 'revenue' ? '1.1rem' : '1.4rem',
          boxShadow: `0 8px 20px ${cfg.shadow}`, fontWeight: '900', color: 'white',
          flexShrink: 0,
        }}>{cfg.icon}</div>
      </div>
    </div>
  );
}

function MiniBar({ label, value, max, color }) {
  const pct = Math.max((value / Math.max(max, 1)) * 100, 2);
  return (
    <div style={{ marginBottom: '14px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
        <span style={{ color: '#555', fontSize: '0.82rem', fontWeight: '600' }}>{label}</span>
        <span style={{ color: '#1a1a2e', fontSize: '0.82rem', fontWeight: '700' }}>{value}</span>
      </div>
      <div style={{ height: '8px', background: '#f0f0f0', borderRadius: '4px', overflow: 'hidden' }}>
        <div style={{ height: '100%', width: `${pct}%`, background: color, borderRadius: '4px', transition: 'width 1s ease' }} />
      </div>
    </div>
  );
}

export default function AdminDashboard() {
  const [data, setData]         = useState(null);
  const [loading, setLoading]   = useState(true);
  const [activeTab, setActiveTab] = useState('overview');
  const [suggestions, setSuggestions] = useState([]);
  const [updatingId, setUpdatingId]   = useState(null);

  useEffect(() => { fetchDashboard(); }, []);

  const fetchDashboard = async () => {
    setLoading(true);
    try {
      const [eventsRes, bookingsRes] = await Promise.all([
        API.get('/events'),
        API.get('/bookings/all/bookings'),
      ]);
      const events   = eventsRes.data?.events   || eventsRes.data   || [];
      const bookings = bookingsRes.data?.bookings || bookingsRes.data || [];

      const paidBookings      = bookings.filter(b => b.paymentStatus === 'paid' || b.status === 'confirmed');
      const totalRevenue      = paidBookings.reduce((s, b) => s + (b.totalAmount || b.totalPrice || b.amount || 0), 0);
      const confirmedBookings = bookings.filter(b => b.status === 'confirmed');
      const cancelledBookings = bookings.filter(b => b.status === 'cancelled');
      const pendingBookings   = bookings.filter(b => b.status === 'pending');

      const now = new Date();
      const monthlyData = {};
      for (let i = 5; i >= 0; i--) {
        const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
        monthlyData[d.toLocaleString('default', { month: 'short', year: '2-digit' })] = 0;
      }
      paidBookings.forEach(b => {
        const key = new Date(b.createdAt || b.bookingDate).toLocaleString('default', { month: 'short', year: '2-digit' });
        if (monthlyData[key] !== undefined) monthlyData[key] += (b.totalAmount || b.totalPrice || b.amount || 0);
      });

      const thisMonthKey = now.toLocaleString('default', { month: 'short', year: '2-digit' });
      const lastMonthKey = new Date(now.getFullYear(), now.getMonth() - 1, 1).toLocaleString('default', { month: 'short', year: '2-digit' });
      const thisMonthRev = monthlyData[thisMonthKey] || 0;
      const lastMonthRev = monthlyData[lastMonthKey] || 0;
      const momGrowth    = lastMonthRev > 0 ? (((thisMonthRev - lastMonthRev) / lastMonthRev) * 100).toFixed(1) : 0;

      const TARGET_MONTHLY  = 50000;
      const thisMonthProfit = thisMonthRev * 0.70;
      const thisMonthCost   = thisMonthRev * 0.30;
      const totalProfit     = totalRevenue * 0.70;
      const totalCost       = totalRevenue * 0.30;
      const targetAchieved  = Math.min((thisMonthRev / TARGET_MONTHLY) * 100, 100).toFixed(0);

      const catMap = {};
      events.forEach(e => { catMap[e.category] = (catMap[e.category] || 0) + 1; });

      try {
        const sugRes = await API.get('/suggestions');
        setSuggestions(sugRes.data || []);
      } catch { setSuggestions([]); }

      setData({
        events, bookings, totalRevenue, totalCost, totalProfit,
        confirmedBookings, cancelledBookings, pendingBookings,
        monthlyData, catMap, TARGET_MONTHLY,
        thisMonthRev, thisMonthCost, thisMonthProfit,
        isProfit: thisMonthProfit >= 0, totalIsProfit: totalProfit >= 0,
        targetAchieved, momGrowth,
        totalUsers: [...new Set(bookings.map(b => String(b.userId || b.user)))].filter(Boolean).length,
      });
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const updateStatus = async (id, status) => {
    setUpdatingId(id);
    try {
      await API.patch(`/suggestions/${id}`, { status });
      setSuggestions(prev => prev.map(s => s._id === id ? { ...s, status } : s));
    } catch { alert('Failed to update'); }
    finally { setUpdatingId(null); }
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '80vh', flexDirection: 'column', gap: '1rem' }}>
      <div style={{ width: '48px', height: '48px', border: '4px solid #f0f0f0', borderTop: '4px solid #c9a99a', borderRadius: '50%', animation: 'spin 1s linear infinite' }} />
      <p style={{ color: '#999', fontWeight: '600', fontSize: '0.9rem' }}>Loading dashboard...</p>
    </div>
  );
  if (!data) return <div style={{ padding: '2rem', color: '#c62828' }}>❌ Failed to load.</div>;

  const maxMonthly = Math.max(...Object.values(data.monthlyData), 1);
  const pendingSug = suggestions.filter(s => s.status === 'pending').length;

  const TABS = [
    { id: 'overview',    label: 'Overview',    icon: '🏠' },
    { id: 'revenue',     label: 'Revenue',     icon: '💰' },
    { id: 'events',      label: 'Events',      icon: '🎭' },
    { id: 'suggestions', label: `Ideas${pendingSug > 0 ? ` (${pendingSug})` : ''}`, icon: '💡' },
  ];

  return (
    <div style={{ fontFamily: "'DM Sans', sans-serif", padding: '2rem', background: '#f7f8fc', minHeight: '100vh' }}>
      <style>{STYLES}</style>

      {/* Header */}
      <div style={{ marginBottom: '2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
        <div>
          <h1 style={{ color: '#1a1a2e', fontWeight: '900', fontSize: '2rem', margin: '0 0 4px', fontFamily: "'Cormorant Garamond', serif" }}>
            Admin Dashboard
          </h1>
          <p style={{ color: '#999', fontSize: '0.85rem', margin: 0 }}>
            📅 {new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
          </p>
        </div>
        <button onClick={fetchDashboard} style={{
          background: 'linear-gradient(135deg,#c9a99a,#b8887a)', color: 'white',
          border: 'none', padding: '10px 20px', borderRadius: '14px',
          cursor: 'pointer', fontWeight: '700', fontSize: '0.85rem',
          boxShadow: '0 4px 14px rgba(201,169,154,0.4)',
        }}>🔄 Refresh</button>
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: '8px', marginBottom: '2rem', background: 'white', padding: '6px', borderRadius: '16px', boxShadow: '0 2px 12px rgba(0,0,0,0.06)', width: 'fit-content' }}>
        {TABS.map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)} style={{
            padding: '8px 20px', borderRadius: '12px', border: 'none', cursor: 'pointer',
            fontWeight: '700', fontSize: '0.82rem', transition: 'all 0.2s ease',
            background: activeTab === tab.id ? 'linear-gradient(135deg,#c9a99a,#b8887a)' : 'transparent',
            color: activeTab === tab.id ? 'white' : '#999',
            boxShadow: activeTab === tab.id ? '0 4px 12px rgba(201,169,154,0.4)' : 'none',
          }}>
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {/* ── OVERVIEW ── */}
      {activeTab === 'overview' && (
        <div style={{ animation: 'fadeUp 0.4s ease' }}>

          {/* Stats Grid */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '1.2rem', marginBottom: '1.5rem' }}>
            <StatCard type="revenue"  label="Total Revenue"  value={`₹${data.totalRevenue.toLocaleString()}`}  sub={`${data.momGrowth >= 0 ? '+' : ''}${data.momGrowth}% vs last month`} trend={data.momGrowth >= 0 ? 'up' : 'down'} />
            <StatCard type="bookings" label="Total Bookings"  value={data.bookings.length}                      sub={`${data.confirmedBookings.length} confirmed`} trend="up" />
            <StatCard type="events"   label="Total Events"    value={data.events.length}                        sub={`${data.events.filter(e => new Date(e.date) > new Date()).length} upcoming`} trend="up" />
            <StatCard type="users"    label="Total Users"     value={data.totalUsers}                           sub="registered" trend="neutral" />
            <StatCard type="cancel"   label="Cancellations"   value={data.cancelledBookings.length}             sub={`${((data.cancelledBookings.length / Math.max(data.bookings.length, 1)) * 100).toFixed(0)}% rate`} trend="down" />
            <StatCard type="pending"  label="Pending"         value={data.pendingBookings.length}               sub="awaiting" trend="neutral" />
          </div>

          {/* Bottom Row */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.2rem' }}>

            {/* Monthly Chart */}
            <div style={{ background: 'white', borderRadius: '24px', padding: '1.8rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0' }}>
              <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 1.5rem', fontSize: '1rem' }}>📊 Revenue Trend</h3>
              <div style={{ display: 'flex', alignItems: 'flex-end', gap: '10px', height: '140px' }}>
                {Object.entries(data.monthlyData).map(([month, rev], i, arr) => {
                  const pct = (rev / maxMonthly) * 100;
                  const isThis = i === arr.length - 1;
                  return (
                    <div key={month} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px' }}>
                      <span style={{ color: '#1a1a2e', fontSize: '0.6rem', fontWeight: '700' }}>
                        {rev > 999 ? `₹${(rev / 1000).toFixed(0)}k` : rev > 0 ? `₹${rev}` : ''}
                      </span>
                      <div style={{
                        width: '100%', borderRadius: '8px 8px 0 0',
                        background: isThis ? 'linear-gradient(180deg,#f093fb,#f5576c)' : 'linear-gradient(180deg,#e0e0e0,#d0d0d0)',
                        height: `${Math.max(pct, 4)}%`, minHeight: '6px',
                        transition: 'height 1s ease',
                        boxShadow: isThis ? '0 4px 12px rgba(240,147,251,0.4)' : 'none',
                      }} />
                      <span style={{ color: isThis ? '#f5576c' : '#aaa', fontSize: '0.62rem', fontWeight: isThis ? '700' : '400' }}>{month}</span>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Target + P&L */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.2rem' }}>

              {/* Target */}
              <div style={{ background: 'white', borderRadius: '24px', padding: '1.5rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0', flex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                  <div>
                    <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 2px', fontSize: '0.95rem' }}>🎯 Monthly Target</h3>
                    <p style={{ color: '#999', fontSize: '0.76rem', margin: 0 }}>₹{data.thisMonthRev.toLocaleString()} of ₹{data.TARGET_MONTHLY.toLocaleString()}</p>
                  </div>
                  <div style={{
                    width: '54px', height: '54px', borderRadius: '50%',
                    background: `conic-gradient(${data.targetAchieved >= 100 ? '#43e97b' : '#c9a99a'} ${data.targetAchieved * 3.6}deg, #f0f0f0 0deg)`,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                  }}>
                    <div style={{ width: '42px', height: '42px', background: 'white', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.7rem', fontWeight: '800', color: '#1a1a2e' }}>
                      {data.targetAchieved}%
                    </div>
                  </div>
                </div>
                <div style={{ height: '8px', background: '#f0f0f0', borderRadius: '4px', overflow: 'hidden' }}>
                  <div style={{ height: '100%', width: `${data.targetAchieved}%`, background: data.targetAchieved >= 100 ? 'linear-gradient(90deg,#43e97b,#38f9d7)' : 'linear-gradient(90deg,#c9a99a,#b8887a)', borderRadius: '4px', transition: 'width 1s ease' }} />
                </div>
              </div>

              {/* P&L */}
              <div style={{
                background: data.totalIsProfit ? 'linear-gradient(135deg,#e8f5e9,#f1f8e9)' : 'linear-gradient(135deg,#fdeee9,#fad4cc)',
                borderRadius: '24px', padding: '1.5rem',
                border: `1px solid ${data.totalIsProfit ? '#c8e6c9' : '#f0c4b8'}`, flex: 1,
              }}>
                <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 1rem', fontSize: '0.95rem' }}>
                  {data.totalIsProfit ? '📈 Net Profit' : '📉 Net Loss'}
                </h3>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  {[
                    { k: 'Revenue', v: `₹${data.totalRevenue.toLocaleString()}`, c: '#1a1a2e' },
                    { k: 'Cost 30%', v: `₹${Math.round(data.totalCost).toLocaleString()}`, c: '#c62828' },
                    { k: 'Profit', v: `₹${Math.round(data.totalProfit).toLocaleString()}`, c: data.totalIsProfit ? '#2e7d32' : '#c62828' },
                  ].map(item => (
                    <div key={item.k} style={{ textAlign: 'center' }}>
                      <p style={{ color: '#999', fontSize: '0.68rem', fontWeight: '700', margin: '0 0 4px', textTransform: 'uppercase' }}>{item.k}</p>
                      <p style={{ color: item.c, fontWeight: '900', fontSize: '0.95rem', margin: 0 }}>{item.v}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── REVENUE ── */}
      {activeTab === 'revenue' && (
        <div style={{ animation: 'fadeUp 0.4s ease' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: '1.2rem', marginBottom: '1.5rem' }}>
            {[
              { label: 'This Month Revenue', val: `₹${data.thisMonthRev.toLocaleString()}`, color: '#c9a99a', bg: 'linear-gradient(135deg,#fdf0eb,#fde8e0)' },
              { label: data.isProfit ? '📈 This Month Profit' : '📉 This Month Loss', val: `₹${Math.round(Math.abs(data.thisMonthProfit)).toLocaleString()}`, color: data.isProfit ? '#2e7d32' : '#c62828', bg: data.isProfit ? 'linear-gradient(135deg,#e8f5e9,#f1f8e9)' : 'linear-gradient(135deg,#fdeee9,#fad4cc)' },
              { label: 'This Month Cost', val: `₹${Math.round(data.thisMonthCost).toLocaleString()}`, color: '#8a7040', bg: 'linear-gradient(135deg,#fef9ec,#fdf0d8)' },
            ].map((item, i) => (
              <div key={i} className="card-hover" style={{ background: item.bg, borderRadius: '24px', padding: '1.6rem', border: '1px solid #f0f0f0', boxShadow: '0 4px 20px rgba(0,0,0,0.06)' }}>
                <p style={{ color: '#999', fontSize: '0.72rem', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '1px', margin: '0 0 10px' }}>{item.label}</p>
                <p style={{ color: item.color, fontSize: '2rem', fontWeight: '900', margin: 0, fontFamily: "'Cormorant Garamond', serif" }}>{item.val}</p>
              </div>
            ))}
          </div>

          <div style={{ background: 'white', borderRadius: '24px', padding: '1.8rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0', marginBottom: '1.5rem' }}>
            <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 1.5rem', fontSize: '1rem' }}>📊 6-Month Revenue</h3>
            <div style={{ display: 'flex', alignItems: 'flex-end', gap: '14px', height: '160px' }}>
              {Object.entries(data.monthlyData).map(([month, rev], i, arr) => {
                const pct = (rev / maxMonthly) * 100;
                const isThis = i === arr.length - 1;
                return (
                  <div key={month} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px' }}>
                    <span style={{ color: '#1a1a2e', fontSize: '0.65rem', fontWeight: '700' }}>
                      {rev > 999 ? `₹${(rev / 1000).toFixed(0)}k` : rev > 0 ? `₹${rev}` : '-'}
                    </span>
                    <div style={{
                      width: '100%', borderRadius: '10px 10px 0 0',
                      background: isThis ? 'linear-gradient(180deg,#c9a99a,#b8887a)' : '#e8e8e8',
                      height: `${Math.max(pct, 4)}%`, minHeight: '8px', transition: 'height 1s ease',
                      boxShadow: isThis ? '0 4px 14px rgba(201,169,154,0.5)' : 'none',
                    }} />
                    <span style={{ color: isThis ? '#b8887a' : '#aaa', fontSize: '0.68rem', fontWeight: isThis ? '700' : '400' }}>{month}</span>
                  </div>
                );
              })}
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.2rem' }}>
            <div style={{ background: 'white', borderRadius: '24px', padding: '1.5rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0' }}>
              <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 1.2rem', fontSize: '0.95rem' }}>💰 P&L Breakdown</h3>
              {[
                { label: 'Gross Revenue', val: `₹${data.totalRevenue.toLocaleString()}`, color: '#2e7d32' },
                { label: 'Operational Cost (30%)', val: `- ₹${Math.round(data.totalCost).toLocaleString()}`, color: '#c62828' },
                { label: data.totalIsProfit ? 'Net Profit ✅' : 'Net Loss ❌', val: `₹${Math.abs(Math.round(data.totalProfit)).toLocaleString()}`, color: data.totalIsProfit ? '#2e7d32' : '#c62828' },
              ].map((item, i) => (
                <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 0', borderBottom: i < 2 ? '1px solid #f5f5f5' : 'none' }}>
                  <span style={{ color: '#666', fontSize: '0.84rem' }}>{item.label}</span>
                  <span style={{ color: item.color, fontWeight: '800', fontSize: '0.88rem' }}>{item.val}</span>
                </div>
              ))}
            </div>
            <div style={{ background: 'white', borderRadius: '24px', padding: '1.5rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0' }}>
              <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 1.2rem', fontSize: '0.95rem' }}>🎯 Target Analysis</h3>
              {[
                { label: 'Monthly Target', val: `₹${data.TARGET_MONTHLY.toLocaleString()}`, color: '#1a1a2e' },
                { label: 'This Month Earned', val: `₹${data.thisMonthRev.toLocaleString()}`, color: '#1a1a2e' },
                { label: 'Achievement', val: `${data.targetAchieved}%`, color: data.targetAchieved >= 100 ? '#2e7d32' : '#c9a99a' },
                { label: 'Remaining', val: `₹${Math.max(0, data.TARGET_MONTHLY - data.thisMonthRev).toLocaleString()}`, color: '#c62828' },
                { label: 'MoM Growth', val: `${data.momGrowth >= 0 ? '+' : ''}${data.momGrowth}%`, color: data.momGrowth >= 0 ? '#2e7d32' : '#c62828' },
              ].map((item, i) => (
                <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 0', borderBottom: i < 4 ? '1px solid #f5f5f5' : 'none' }}>
                  <span style={{ color: '#666', fontSize: '0.82rem' }}>{item.label}</span>
                  <span style={{ color: item.color, fontWeight: '800', fontSize: '0.84rem' }}>{item.val}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ── EVENTS ── */}
      {activeTab === 'events' && (
        <div style={{ animation: 'fadeUp 0.4s ease' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '1.2rem' }}>
            <div style={{ background: 'white', borderRadius: '24px', padding: '1.5rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0' }}>
              <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 1.2rem', fontSize: '0.95rem' }}>🎭 By Category</h3>
              {Object.entries(data.catMap).map(([cat, count]) => (
                <MiniBar key={cat} label={cat} value={count} max={data.events.length}
                  color="linear-gradient(90deg,#c9a99a,#b8887a)" />
              ))}
            </div>
            <div style={{ background: 'white', borderRadius: '24px', padding: '1.5rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0' }}>
              <h3 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 1.2rem', fontSize: '0.95rem' }}>🏆 All Events</h3>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '400px', overflowY: 'auto' }}>
                {data.events.map((event, i) => {
                  const isUpcoming = new Date(event.date) > new Date();
                  return (
                    <div key={i} className="card-hover" style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '12px 14px', background: '#fafafa', borderRadius: '16px', border: '1px solid #f0f0f0' }}>
                      <div style={{ width: '40px', height: '40px', borderRadius: '12px', background: 'linear-gradient(135deg,#c9a99a,#b8887a)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: '800', fontSize: '0.85rem', flexShrink: 0 }}>{i + 1}</div>
                      <div style={{ flex: 1 }}>
                        <p style={{ color: '#1a1a2e', fontWeight: '700', margin: '0 0 2px', fontSize: '0.87rem' }}>{event.name}</p>
                        <p style={{ color: '#999', fontSize: '0.74rem', margin: 0 }}>{event.category} • {new Date(event.date).toDateString()} • ₹{event.price}</p>
                      </div>
                      <span style={{ padding: '4px 12px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: '700', background: isUpcoming ? '#e8f5e9' : '#f5f5f5', color: isUpcoming ? '#2e7d32' : '#999' }}>
                        {isUpcoming ? 'Upcoming' : 'Past'}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── SUGGESTIONS ── */}
      {activeTab === 'suggestions' && (
        <div style={{ animation: 'fadeUp 0.4s ease' }}>
          <div style={{ display: 'flex', gap: '10px', marginBottom: '1.2rem', flexWrap: 'wrap' }}>
            {[
              { label: 'All', count: suggestions.length, color: '#666', bg: '#f5f5f5' },
              { label: 'Pending', count: suggestions.filter(s => s.status === 'pending').length, color: '#8a7040', bg: '#fef9ec' },
              { label: 'Approved', count: suggestions.filter(s => s.status === 'approved').length, color: '#2e7d32', bg: '#e8f5e9' },
              { label: 'Rejected', count: suggestions.filter(s => s.status === 'rejected').length, color: '#c62828', bg: '#fdeee9' },
            ].map(item => (
              <span key={item.label} style={{ padding: '6px 14px', borderRadius: '20px', background: item.bg, color: item.color, fontSize: '0.78rem', fontWeight: '700' }}>
                {item.label}: {item.count}
              </span>
            ))}
          </div>

          <div style={{ background: 'white', borderRadius: '24px', padding: '1.5rem', boxShadow: '0 4px 24px rgba(0,0,0,0.07)', border: '1px solid #f0f0f0' }}>
            {suggestions.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '4rem', color: '#ccc' }}>
                <div style={{ fontSize: '4rem', marginBottom: '1rem' }}>💡</div>
                <p style={{ fontWeight: '700', color: '#999' }}>No suggestions yet!</p>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
                {suggestions.map(s => (
                  <div key={s._id} className="card-hover" style={{
                    padding: '1.3rem', background: '#fafafa', borderRadius: '18px',
                    border: `1px solid ${s.status === 'approved' ? '#c8e6c9' : s.status === 'rejected' ? '#f0c4b8' : '#f0f0f0'}`,
                    animation: 'fadeUp 0.4s ease',
                  }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px', flexWrap: 'wrap', gap: '8px' }}>
                      <div>
                        <h4 style={{ color: '#1a1a2e', fontWeight: '800', margin: '0 0 6px', fontSize: '0.95rem' }}>{s.title}</h4>
                        <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
                          <span style={{ background: '#fdf0eb', color: '#b8887a', padding: '3px 10px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: '700' }}>{s.category}</span>
                          <span style={{ padding: '3px 10px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: '700', background: s.status === 'approved' ? '#e8f5e9' : s.status === 'rejected' ? '#fdeee9' : '#fef9ec', color: s.status === 'approved' ? '#2e7d32' : s.status === 'rejected' ? '#c62828' : '#8a7040' }}>{s.status?.toUpperCase()}</span>
                        </div>
                      </div>
                      <span style={{ color: '#aaa', fontSize: '0.74rem' }}>{new Date(s.createdAt).toLocaleDateString('en-IN')}</span>
                    </div>
                    <p style={{ color: '#666', fontSize: '0.83rem', margin: '8px 0 12px', lineHeight: '1.6' }}>{s.description}</p>
                    {s.status === 'pending' && (
                      <div style={{ display: 'flex', gap: '8px' }}>
                        <button onClick={() => updateStatus(s._id, 'approved')} disabled={updatingId === s._id}
                          style={{ padding: '8px 18px', background: 'linear-gradient(135deg,#43e97b,#38f9d7)', color: 'white', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: '700', fontSize: '0.78rem' }}>
                          ✅ Approve
                        </button>
                        <button onClick={() => updateStatus(s._id, 'rejected')} disabled={updatingId === s._id}
                          style={{ padding: '8px 18px', background: '#fdeee9', color: '#c62828', border: '1px solid #f0c4b8', borderRadius: '12px', cursor: 'pointer', fontWeight: '700', fontSize: '0.78rem' }}>
                          ❌ Reject
                        </button>
                      </div>
                    )}
                    {s.status !== 'pending' && (
                      <button onClick={() => updateStatus(s._id, 'pending')}
                        style={{ padding: '6px 14px', background: 'white', color: '#999', border: '1px solid #e0e0e0', borderRadius: '10px', cursor: 'pointer', fontWeight: '600', fontSize: '0.75rem' }}>
                        🔄 Reset
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
